          `,...i}),t&&c.jsx("p",{className:"mt-1.5 text-sm text-accent-error",children:t}),n&&!t&&c.jsx("p",{className:"mt-1.5 text-sm text-text-secondary",children:n})]}));z2.displayName="TextArea";const Qg=S.forwardRef(({label:e,error:t,helperText:n,className:r="",onChange:i,value:a,...s},o)=>c.jsxs("div",{className:"w-full",children:[e&&c.jsx("label",{className:"block text-sm font-medium text-text-secondary mb-2",children:e}),c.jsx("input",{ref:o,className:`
